  'tools.youtube-script-generator.faq.2.a': { en: 'For most styles, bullet points work better than word-for-word scripts. Only memorize key transitions and the hook.', zh: '对于大多数风格，要点提纲比逐字脚本效果更好。只需记住关键过渡和钩子。' },
